#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, R; scanf("%d %d", &N, &R);
        int *a = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        if (N > 0) R %= N;
        int start = (N - R) % N; // index of new head
        for (int i = 0; i < N; ++i) {
            int idx = (start + i) % N;
            printf("%d", a[idx]);
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
        free(a);
    }
    return 0;
}

