const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  let R = Number(input[idx++]);
  const arr = [];
  for (let i = 0; i < N; i++) arr.push(Number(input[idx++]));
  if (N) {
    R %= N;
    const start = (N - R) % N;
    const rotated = [];
    for (let i = 0; i < N; i++) rotated.push(arr[(start + i) % N]);
    outputs.push(rotated.join(' '));
  } else {
    outputs.push('');
  }
}
